package com.restaurantcraft.network; import com.restaurantcraft.blockentity.RestaurantManagementBlockEntity; import net.minecraft.core.BlockPos; import net.minecraft.network.FriendlyByteBuf; import net.minecraft.server.level.ServerPlayer; import net.minecraftforge.network.NetworkEvent; import java.util.function.Supplier; public record C2SChangeRestaurantNamePacket(BlockPos pos,String name){ public static void encode(C2SChangeRestaurantNamePacket p,FriendlyByteBuf b){b.writeBlockPos(p.pos);b.writeUtf(p.name,64);} public static C2SChangeRestaurantNamePacket decode(FriendlyByteBuf b){return new C2SChangeRestaurantNamePacket(b.readBlockPos(),b.readUtf(64));} public static void handle(C2SChangeRestaurantNamePacket p,Supplier<NetworkEvent.Context> c){c.get().enqueueWork(()->{ServerPlayer sp=c.get().getSender(); if(sp!=null&&sp.level().getBlockEntity(p.pos) instanceof RestaurantManagementBlockEntity be&&be.isOwner(sp)){be.data.restaurantName=p.name;be.setChanged();}}); c.get().setPacketHandled(true);} }
